MA60:=MA(CLOSE,60);
MA120:=MA(CLOSE,120);

{长期多头排列}
DUOTOU:=MA60>MA120;

{30日前的均线差值}
MA60_30:=REF(MA60,30);
MA120_30:=REF(MA120,30);
CHAZHI_30:=MA60_30-MA120_30;

{当前均线差值}
CHAZHI:=MA60-MA120;

{差值变化幅度 - 近似平行 = 近30日差值变化<30%}
BIANHUA:=ABS(CHAZHI-CHAZHI_30)/CHAZHI_30*100;
PINGXING:=BIANHUA<30;

{综合选股条件}
XX:DUOTOU AND PINGXING;
